Set-StrictMode -Version 2.0
function Invoke-GodModeWindowsDoctor { param([string]$Project='.')
$r=Initialize-GodModeStructure $Project; $pp=Resolve-GodModeProjectPath $Project; $os=$null; try{$os=Get-CimInstance Win32_OperatingSystem -ErrorAction Stop}catch{}
$ascii=-not($pp.ToCharArray()|?{[int][char]$_ -gt 127}|select -First 1); $degraded=@(); if($pp -match 'OneDrive'){$degraded+='project_path_on_onedrive'}; if(-not $ascii){$degraded+='project_path_non_ascii'}
$cap=@{schema_version=1;generated_at=Get-GodModeIso;is_windows=($env:OS -like '*Windows*');windows_version=if($os){$os.Caption}else{$null};windows_build=if($os){$os.BuildNumber}else{$null};windows_edition=if($os){$os.OperatingSystemSKU}else{$null};windows_11_recommended_baseline=if($os -and $os.Caption -match 'Windows 11'){$true}else{$false};windows_10_best_effort=if($os -and $os.Caption -match 'Windows 10'){$true}else{$false};conpty_likely_available=$true;powershell_executable=(Get-Process -Id $PID).Path;powershell_version=$PSVersionTable.PSVersion.ToString();powershell_edition=$PSVersionTable.PSEdition;pwsh_available=[bool](Get-Command pwsh -ErrorAction SilentlyContinue);powershell_execution_policy_current_user=[string](Get-ExecutionPolicy -Scope CurrentUser);powershell_execution_policy_process=[string](Get-ExecutionPolicy -Scope Process);console_utf8_supported=$true;ansi_supported=$true;visible_window_supported=$true;start_process_supported=$true;elevated_admin_context=([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator);codex_native_windows_mode_possible=[bool](Get-Command codex -ErrorAction SilentlyContinue);codex_wsl_mode_possible=[bool](Get-Command wsl -ErrorAction SilentlyContinue);codex_sandbox_mode_detected_or_unknown='unknown';WindowsApps_path_risk=($env:PATH -match 'WindowsApps');user_profile_path=$env:USERPROFILE;codex_home_path=$env:CODEX_HOME;temp_path=$env:TEMP;project_path=$pp;project_path_ascii_safe=$ascii;project_path_on_onedrive=($pp -match 'OneDrive');project_path_unc=$pp.StartsWith('\\');project_path_mapped_drive=($pp -match '^[A-Za-z]:');project_path_long_path_risk=($pp.Length -gt 180);username_non_ascii=[bool]($env:USERNAME.ToCharArray()|?{[int][char]$_ -gt 127}|select -First 1);project_path_non_ascii=(-not $ascii);git_available=[bool](Get-Command git -ErrorAction SilentlyContinue);git_worktree_available=[bool](Get-Command git -ErrorAction SilentlyContinue);git_repo_detected=(Test-Path (Join-Path $pp '.git'));node_available_verified=[bool](Get-Command node -ErrorAction SilentlyContinue);npm_available_verified=[bool](Get-Command npm -ErrorAction SilentlyContinue);npx_available_verified=[bool](Get-Command npx -ErrorAction SilentlyContinue);rg_available_verified=[bool](Get-Command rg -ErrorAction SilentlyContinue);python_available_verified=[bool](Get-Command python -ErrorAction SilentlyContinue);dotnet_available_verified=[bool](Get-Command dotnet -ErrorAction SilentlyContinue);gh_available_verified=[bool](Get-Command gh -ErrorAction SilentlyContinue);code_available_verified=[bool](Get-Command code -ErrorAction SilentlyContinue);browser_use_windows_risk='unknown_until_probe';apply_patch_windows_risk='fallback_required';network_sandbox_risk='unknown';wsl_bridge_risk=if(Get-Command wsl -ErrorAction SilentlyContinue){'optional'}else{'not_available'};recommended_execution_mode='windows-native-safe';degraded_reasons=$degraded;blockers=@()}
Write-GodModeJsonAtomic (Join-GodModePath $r 'state/windows-capabilities.json') $cap|Out-Null; Add-GodModeJsonLine (Join-GodModePath $r 'memory/windows-capability-ledger.jsonl') @{schema_version=1;created_at=Get-GodModeIso;type='windows_doctor';status=if($degraded.Count){'degraded'}else{'ok'};degraded_reasons=$degraded}; $cap }
